#include <stdio.h>
#include <math.h>

int isPowerPassword(int x) {
    int sqrt_x = sqrt(x);
    for (int i = 2; i <= sqrt_x; i++) {
        if (i * i == x) return 1;
    }
    return 0;
}

int main() {
    int N;
    scanf("%d", &N);
    int passwords[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &passwords[i]);
    }
    for (int i = 0; i < N; i++) {
        if (isPowerPassword(passwords[i])) {
            int count = 0;
            int j = 4;
            while (j < passwords[i]) {
                count++;
                j = (int)pow(++count, 2);
            }
            printf("%d ", count + 1);
        } else {
            int count = 0;
            int j = 0;
            while (j < passwords[i]) {
                count++;
                j = (int)pow(2, count);
            }
            if (j > passwords[i]) {
                int left = (int)pow(2, count - 1);
                int right = j;
                while (left < right) {
                    int mid = (left + right) / 2;
                    if (mid < passwords[i]) {
                        left = mid + 1;
                    } else {
                        right = mid;
                    }
                }
                printf("%d ", count + (int)log2(right - left) + 1);
            } else {
                printf("%d ", count);
            }
        }
    }
    return 0;
}

