import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] passwords = new int[N];
        for (int i = 0; i < N; i++) {
            passwords[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            if (isPowerPassword(passwords[i])) {
                int count = 0;
                int j = 4;
                while (j < passwords[i]) {
                    count++;
                    j = (int)Math.pow(++count, 2);
                }
                System.out.print(count + 1 + " ");
            } else {
                int count = 0;
                int j = 0;
                while (j < passwords[i]) {
                    count++;
                    j = (int)Math.pow(2, count);
                }
                if (j > passwords[i]) {
                    int left = (int)Math.pow(2, count - 1);
                    int right = j;
                    while (left < right) {
                        int mid = (left + right) / 2;
                        if (mid < passwords[i]) {
                            left = mid + 1;
                        } else {
                            right = mid;
                        }
                    }
                    System.out.print(count + (int)(Math.log(right - left) / Math.log(2)) + 1 + " ");
                } else {
                    System.out.print(count + " ");
                }
            }
        }
    }
    public static boolean isPowerPassword(int x) {
        int sqrt_x = (int)Math.sqrt(x);
        for (int i = 2; i <= sqrt_x; i++) {
            if (i * i == x) return true;
        }
        return false;
    }
}

